/* Test driver */
public class Main {
    public static void main(String[] args) {
        Board b = BoardFactory.createEmptyBoard(50);
        b.addLadder(10, 35);
        b.addSnake(20, 5);
        if (b.getFinalPosition(10) != 35) { System.out.println("FAIL: ladder"); System.exit(1); }
        if (b.getFinalPosition(20) != 5) { System.out.println("FAIL: snake"); System.exit(1); }
        if (b.getFinalPosition(15) != 15) { System.out.println("FAIL: normal"); System.exit(1); }
        System.out.println("OK_EFFECTS");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        Board b = BoardFactory.createEmptyBoard(10);
        FixedDice d = new FixedDice(5, 5, 5, 5, 5, 5);
        SnakeAndLadderGame g = new SnakeAndLadderGame(b, d, false);
        g.addPlayer("A");
        g.addPlayer("B");
        g.play(20);
        if (g.getWinner() == null) { System.out.println("FAIL: no winner"); System.exit(1); }
        if (!g.getWinner().getName().equals("A")) { System.out.println("FAIL: wrong winner=" + g.getWinner().getName()); System.exit(1); }
        System.out.println("OK_WINNER");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        Board b = BoardFactory.createEmptyBoard(10);
        FixedDice d = new FixedDice(6, 6, 6);
        SnakeAndLadderGame g = new SnakeAndLadderGame(b, d, false);
        g.addPlayer("Solo");
        g.playTurn();
        int after1 = g.getPlayers().get(0).getPosition();
        if (after1 != 6) { System.out.println("FAIL: first roll pos=" + after1); System.exit(1); }
        g.playTurn();
        int after2 = g.getPlayers().get(0).getPosition();
        if (after2 != 6) { System.out.println("FAIL: overshoot pos=" + after2); System.exit(1); }
        System.out.println("OK_OVERSHOOT");
    }
}
